 1	import { type FC, useState } from 'react';
 2	import type { EnhancedPlanSpecVms } from 'src/plans/details/tabs/Details/components/SettingsSection/utils/types';
 3	
 4	import { FormGroupWithHelpText } from '@components/common/FormGroupWithHelpText/FormGroupWithHelpText';
 5	import ModalForm from '@components/ModalForm/ModalForm';
 6	import type { V1beta1Plan } from '@kubev2v/types';
 7	import { Stack, StackItem, TextInput, ValidatedOptions } from '@patternfly/react-core';
 8	import { getPlanVirtualMachines } from '@utils/crds/plans/selectors';
 9	import { isEmpty } from '@utils/helpers';
10	import { ForkliftTrans, useForkliftTranslation } from '@utils/i18n';
11	
12	import { patchVMTargetName, validateVMTargetName } from '../utils/utils';
13	
14	type EditVirtualMachineTargetNameProps = {
15	  plan: V1beta1Plan;
16	  vmIndex: number;
17	};
18	
19	const EditVirtualMachineTargetName: FC<EditVirtualMachineTargetNameProps> = ({ plan, vmIndex }) => {
20	  const { t } = useForkliftTranslation();
21	  const vms = getPlanVirtualMachines(plan);
22	  const [inputValue, setInputValue] = useState(
23	    (vms as EnhancedPlanSpecVms[])?.[vmIndex]?.targetName ?? '',
24	  );
25	  const [errorMessage, setErrorMessage] = useState<string | null>(null);
26	
27	  const validated = isEmpty(errorMessage) ? ValidatedOptions.default : ValidatedOptions.error;
28	
29	  const vm = getPlanVirtualMachines(plan)[vmIndex];
30	
31	  return (
32	    <ModalForm
33	      title={t('Edit target name')}
34	      onConfirm={async () => patchVMTargetName({ newValue: inputValue, resource: plan, vmIndex })}
35	      isDisabled={
36	        Boolean(validateVMTargetName(inputValue, vms ?? [])) ||
37	        (isEmpty(vm.targetName) && isEmpty(inputValue)) ||
38	        vm.targetName === inputValue
39	      }
40	    >
41	      <Stack hasGutter>
42	        <StackItem>
43	          <ForkliftTrans>
44	            Enter the name you would like the <b>{vm.name}</b> VM to have after migration.
45	          </ForkliftTrans>
46	        </StackItem>
47	        <StackItem>
48	          <FormGroupWithHelpText
49	            validated={validated}
50	            helperTextInvalid={errorMessage}
51	            label={t('VM target name')}
52	          >
53	            <TextInput
54	              value={inputValue}
55	              onChange={(_, val) => {
56	                setInputValue(val);
57	              }}
58	              onBlur={() => {
59	                setErrorMessage(
60	                  validateVMTargetName(
61	                    inputValue,
62	                    vms?.filter((_, index) => index !== vmIndex) ?? [],
63	                  ),
64	                );
65	              }}
66	              onFocus={() => {
67	                setErrorMessage(null);
68	              }}
69	              validated={validated}
70	              data-testid="vm-target-name-input"
71	            />
72	          </FormGroupWithHelpText>
73	        </StackItem>
74	      </Stack>
75	    </ModalForm>
76	  );
77	};
78	
79	export default EditVirtualMachineTargetName;

